    40→export const rescueReducer = createReducer(initialState, {
    41→  [RescueTypes.REQUEST](state: State) {
    42→    return {
    43→      ...state,
    44→      isLoading: true,
    45→      isError: false,
    46→    };
    47→  },
    48→  [RescueTypes.SUCCESS](state: State, { status }: { status: ResgateResponse['status'] }) {
    49→    return {
    50→      ...state,
    51→      status,
    52→      isLoading: false,
    53→      isError: false,
    54→    };
